              {/* Class & Section Manager Modal (Keep as is) */}
              {showClassManager && (
                  <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
                      <div className="bg-white rounded-xl shadow-xl max-w-lg w-full">
