                                                      type="number" 
                                                      value={reviewData.discount || 0}
                                                      onChange={e => setReviewData({...reviewData, discount: Number(e.target.value)})}
                                                      className="w-full border p-2 rounded mt-1"
                                                  />
                                              </div>
                                          </div>
                                      </div>
