                              type="text" placeholder="e.g. Second Term 2024" 
                              className="w-full border p-2 rounded"
                              value={newSessionName} onChange={e => setNewSessionName(e.target.value)}
                          />
                      </div>
                      <div className="min-w-[150px]">
                           <label className="text-sm font-bold text-gray-600 block mb-1">Exam Type</label>
                           <select 
                              className="w-full border p-2 rounded"
                              value={newSessionType} onChange={e => setNewSessionType(e.target.value as ExamType)}
                           >
                               <option value="Monthly Test">Monthly Test</option>
                               <option value="Unit Test">Unit Test</option>
                               <option value="Term Exam">Term Exam</option>
                               <option value="Viva Exam">Viva Exam</option>
                               <option value="Final Exam">Final Exam</option>
                           </select>
                      </div>
                      <button 
                          onClick={handleCreateSession}
                          className="bg-galaxy-900 text-white px-4 py-2 rounded hover:bg-galaxy-800 flex items-center gap-2"
                      >
                          <Plus size={16} /> Create Session
                      </button>
                  </div>

                  {/* List Sessions */}
                  <div className="space-y-3">
                      {state.examSessions.map(session => (
                          <div key={session.id} className="flex items-center justify-between border p-4 rounded-lg bg-white shadow-sm">
                              <div>
                                  <div className="flex items-center gap-2">
                                      <h4 className="font-bold text-lg">{session.name}</h4>
                                      <span className="text-xs bg-gray-100 text-gray-600 px-2 py-0.5 rounded border">{session.type}</span>
                                  </div>
                                  <p className="text-xs text-gray-500">Started: {session.startDate}</p>
                              </div>
                              <div className="flex items-center gap-4">
                                  <div className={`text-sm font-bold ${session.status === 'open' ? 'text-green-600' : 'text-red-500'}`}>
                                      {session.status === 'open' ? 'OPEN FOR ENTRY' : 'CLOSED'}
                                  </div>
                                  <button 
                                      onClick={() => dispatch({ type: 'TOGGLE_EXAM_SESSION_STATUS', payload: session.id })}
                                      className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${session.status === 'open' ? 'bg-green-600' : 'bg-gray-300'}`}
                                  >
                                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${session.status === 'open' ? 'translate-x-6' : 'translate-x-1'}`} />
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>

              {/* Class-wise Result Publishing */}
              <div className="bg-white p-6 rounded-xl border border-galaxy-200 shadow-sm">
                  <h3 className="text-xl font-bold mb-4">Publish Class Results</h3>
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end mb-6">
                       <div className="md:col-span-1">
                           <label className="text-sm font-bold text-gray-600 block mb-1">Select Class</label>
                           <select className="w-full border p-2 rounded" value={publishClassId} onChange={e => { setPublishClassId(e.target.value); setPublishSection(''); }}>
                               <option value="">-- Choose Class --</option>
                               {state.systemClasses.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                           </select>
                       </div>
                       <div className="md:col-span-1">
                           <label className="text-sm font-bold text-gray-600 block mb-1">Select Section</label>
                           <select 
                             className="w-full border p-2 rounded" 
                             value={publishSection} 
                             onChange={e => setPublishSection(e.target.value)}
                             disabled={!publishClassId}
                           >
                               <option value="">All Sections</option>
                               {state.systemClasses.find(c => c.name === publishClassId)?.sections.map(s => <option key={s} value={s}>{s}</option>)}
                           </select>
                       </div>
                       <div className="md:col-span-2">
                           <p className="text-xs text-gray-500 mb-2">
                               Results are hidden from students until published. Publishing applies to all students in the selected class/section.
                           </p>
                       </div>
                  </div>

                  {/* Status Cards */}
                  {publishClassId && (
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in">
                        {state.examSessions.map(session => {
                            const reportsForSession = state.examReports.filter(r => 
                                (r.examSessionId && r.examSessionId === session.id) || 
                                r.term?.trim() === session.name?.trim()
                            );
                            const studentsInClass = state.users.filter(u => 
                                u.role === 'student' && 
                                u.classId?.trim() === publishClassId?.trim() && 
                                (!publishSection || u.section?.trim() === publishSection.trim())
                            );
                            const reportsForClass = reportsForSession.filter(r => studentsInClass.some(s => s.id === r.studentId));
                            const publishedCount = reportsForClass.filter(r => r.published === true || String(r.published) === 'true').length;
                            const totalReports = reportsForClass.length;

                            const isFullyPublished = totalReports > 0 && publishedCount === totalReports;
                            const isPartiallyPublished = publishedCount > 0 && !isFullyPublished;
                            const hasNoReports = totalReports === 0;

                            return (
                                <div key={session.id} className={`border rounded-xl p-4 transition-all ${
                                    isFullyPublished ? 'bg-green-50 border-green-200' : 
                                    hasNoReports ? 'bg-gray-50 border-gray-200 opacity-70' : 'bg-white border-yellow-200 shadow-sm'
                                }`}>
                                    <div className="flex justify-between items-start mb-2">
                                        <h4 className="font-bold text-gray-800">{session.name}</h4>
                                        {isFullyPublished ? <Check size={18} className="text-green-600" /> : <UploadCloud size={18} className="text-gray-400"/>}
                                    </div>
                                    <div className="text-xs space-y-1 mb-4">
                                        <p className="flex justify-between"><span className="text-gray-500">Students:</span><span className="font-mono">{studentsInClass.length}</span></p>
                                        <p className="flex justify-between"><span className="text-gray-500">Reports Found:</span><span className="font-mono">{totalReports}</span></p>
                                        <p className="flex justify-between font-bold"><span className="text-gray-500">Published:</span><span className={`${isFullyPublished ? 'text-green-600' : isPartiallyPublished ? 'text-yellow-600' : 'text-gray-400'}`}>{publishedCount} / {totalReports}</span></p>
                                    </div>
                                    <button 
                                      onClick={() => handlePublishClassResult(session, !isFullyPublished, totalReports)}
                                      disabled={hasNoReports}
                                      className={`w-full py-2 rounded text-sm font-bold transition-colors ${
                                          hasNoReports ? 'bg-gray-200 text-gray-400 cursor-not-allowed' :
                                          isFullyPublished ? 'bg-white border border-red-200 text-red-600 hover:bg-red-50' :
                                          'bg-galaxy-900 text-white hover:bg-galaxy-800'
                                      }`}
                                    >
                                        {hasNoReports ? 'No Data' : isFullyPublished ? 'Unpublish Results' : 'Publish Results'}
                                    </button>
                                </div>
                            );
                        })}
                      </div>
                  )}
              </div>
          </div>
      );
  }

  if ((activeTab === 'system' || activeTab === 'debug') && role === 'developer') {
      return (
          <div>
              <h3 className="text-xl font-bold mb-6 text-red-700 flex items-center gap-2">
                  <AlertTriangle /> Dangerous Zone
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Receipt Counter */}
                  <div className="bg-white border border-red-200 p-6 rounded-xl shadow-sm">
                      <h4 className="font-bold mb-2">Receipt Counter Reset</h4>
                      <p className="text-sm text-gray-600 mb-4">
                          Current Next Receipt #: <strong>{state.receiptCounter}</strong><br/>
                      </p>
                      <div className="flex gap-2">
                          <input type="number" value={resetVal} onChange={e => setResetVal(parseInt(e.target.value))} className="border p-2 rounded w-24" />
                          <button onClick={handleResetReceipt} className="bg-red-600 text-white px-4 py-2 rounded hover:bg-red-700 flex items-center gap-2"><RefreshCw size={16} /> Reset Counter</button>
                      </div>
                  </div>

                  {/* Hard Database Reset */}
                  <div className="bg-red-50 border border-red-300 p-6 rounded-xl shadow-sm">
                      <h4 className="font-bold mb-2 text-red-900 flex items-center gap-2">
                          <Database size={18}/> Hard Reset Database
                      </h4>
                      <p className="text-sm text-red-800 mb-4">
                          This action will <strong>permanently delete all data</strong> from Firestore (Users, Assignments, Fees, etc.) and restore the initial system defaults.
                          <br/><br/>
                          <strong>Use this only if the database is corrupted or you want to restart the demo.</strong>
                      </p>
                      <button onClick={handleHardReset} className="w-full bg-red-700 text-white px-4 py-3 rounded hover:bg-red-800 flex items-center justify-center gap-2 font-bold shadow-sm"><AlertTriangle size={18} /> WIPE & RESET DATABASE</button>
                  </div>
              </div>
          </div>
      )
  }

  return <div>Welcome Admin</div>;
};

export default AdminView;

import React, { useState } from 'react';
import { useAppStore } from '../services/store';
import { User, Role } from '../types';
import { Shield, BookOpen, Calculator, UserCheck, Lock, Mail, User as UserIcon, TestTube, Check } from 'lucide-react';
import { createUserWithEmailAndPassword, signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../services/firebase';

const Auth: React.FC = () => {
  const { state, dispatch } = useAppStore();
  const [isLogin, setIsLogin] = useState(true);

  // Login State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  // Register State
  const [regForm, setRegForm] = useState<Partial<User>>({
    name: '', email: '', role: 'student', phone: '', address: '',
    classId: '', section: '', annualFee: 0, discount: 0, subjects: [], password: ''
  });
  const [regSuccess, setRegSuccess] = useState('');

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    try {
        // 1. Attempt Firebase Auth Login
        await signInWithEmailAndPassword(auth, email, password);

        // 2. If successful, find the user profile in our loaded state
        // Note: In a real app, you might fetch this specific user doc here if not loaded.
        const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());

        if (user) {
            if (user.status !== 'active' && user.role !== 'developer') {
                setError('Your account is pending approval by an administrator.');
                return;
            }
            dispatch({ type: 'LOGIN', payload: user });
        } else {
            // Edge case: Auth exists but Firestore profile missing/not loaded
            setError('User profile not found in database.');
        }

    } catch (firebaseError: any) {
        console.log("Firebase auth failed, trying mock fallback...", firebaseError.code);

        // 3. Fallback for Pre-seeded Demo Users (who don't exist in Firebase Auth)
        const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());

        if (user && user.password === password) {
            if (user.status !== 'active') {
                setError('Your account is pending approval by an administrator.');
                return;
            }
            dispatch({ type: 'LOGIN', payload: user });
        } else {
            setError(firebaseError.code === 'auth/invalid-credential' ? 'Invalid credentials' : 'Login failed: ' + firebaseError.message);
        }
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!regForm.password || regForm.password.length < 6) {
        setError('Password must be at least 6 characters long.');
        return;
    }

    // Developer role logic kept in backend logic for extensibility
    const isDev = regForm.role === 'developer';

    try {
        // 1. Create User in Firebase Auth
        const userCredential = await createUserWithEmailAndPassword(auth, regForm.email!, regForm.password);
        const uid = userCredential.user.uid;

        // 2. Create User Profile in Firestore
        const newUser: User = {
            id: uid, // Use the Firebase Auth UID
            name: regForm.name || '',
            email: regForm.email || '',
            role: regForm.role as Role,
            allowedRoles: [regForm.role as Role],
            password: 'password', // Store dummy in DB, actual auth handled by Firebase
            status: isDev ? 'active' : 'pending',
            phone: regForm.phone,
            address: regForm.address,
            annualFee: 0, 
            discount: 0,
            totalPaid: 0,
            // Use conditional spread to avoid undefined values
            ...(regForm.role === 'student' && regForm.classId ? { classId: regForm.classId } : {}),
            ...(regForm.role === 'student' && regForm.section ? { section: regForm.section } : {}),
            ...(regForm.role === 'teacher' && regForm.subjects ? { subjects: regForm.subjects } : {})
        };

        dispatch({ type: 'ADD_USER', payload: newUser });
        setRegSuccess(isDev ? 'Developer Account Created! Please Login.' : 'Registration submitted. Please wait for approval.');
        setRegForm({ name: '', email: '', role: 'student', phone: '', address: '', classId: '', section: '', annualFee: 0, discount: 0, subjects: [], password: '' });

        setTimeout(() => {
            setRegSuccess('');
            setIsLogin(true);
        }, 3000);

    } catch (err: any) {
        console.error("Registration Error:", err);
        if (err.code === 'auth/email-already-in-use') {
            setError('This email is already registered.');
        } else {
            setError(err.message || 'Registration failed.');
        }
    }
  };

  const toggleSubject = (subjectName: string) => {
      const currentSubjects = regForm.subjects || [];
      if (currentSubjects.includes(subjectName)) {
          setRegForm({ ...regForm, subjects: currentSubjects.filter(s => s !== subjectName) });
      } else {
          setRegForm({ ...regForm, subjects: [...currentSubjects, subjectName] });
      }
  };

  const selectedClassData = state.systemClasses.find(c => c.name === regForm.classId);

  return (
    <div className="min-h-screen bg-gradient-to-br from-galaxy-900 via-galaxy-800 to-galaxy-600 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-4xl w-full flex flex-col md:flex-row gap-8">

        {/* Left Side: Branding */}
        <div className="md:w-1/3 flex flex-col justify-center border-r border-gray-100 pr-8">
            <div className="w-16 h-16 bg-gold-400 rounded-xl flex items-center justify-center text-galaxy-900 font-bold text-3xl mb-6">
                G
            </div>
            <h1 className="text-3xl font-bold text-galaxy-900 mb-2">Galaxy Hotel</h1>
            <h2 className="text-xl font-medium text-galaxy-600 mb-6">& Tourism School</h2>
            <p className="text-gray-500 text-sm leading-relaxed">
                Welcome to the official portal. Manage assignments, examinations, fees, and more with our integrated role-based system.
            </p>
            <div className="mt-8 pt-6 border-t border-gray-100">
                <p className="text-xs text-gray-400">System Version 2.0.0</p>
            </div>
        </div>

        {/* Right Side: Form */}
        <div className="md:w-2/3">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold text-gray-800">{isLogin ? 'Sign In' : 'Create Account'}</h3>
                <button 
                    onClick={() => { setIsLogin(!isLogin); setError(''); setRegSuccess(''); }}
                    className="text-sm text-galaxy-600 font-semibold hover:underline"
                >
                    {isLogin ? 'Need an account?' : 'Already have an account?'}
                </button>
            </div>

            {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
            {regSuccess && <div className="bg-green-50 text-green-600 p-3 rounded mb-4 text-sm">{regSuccess}</div>}

            {isLogin ? (
                <>
                <form onSubmit={handleLogin} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
                        <div className="relative">
                            <Mail className="absolute left-3 top-2.5 text-gray-400" size={18} />
                            <input 
                                type="email" 
                                className="w-full border pl-10 p-2 rounded-lg focus:ring-2 focus:ring-galaxy-500 outline-none"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                placeholder="name@galaxy.edu.np"
                                required
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                        <div className="relative">
                            <Lock className="absolute left-3 top-2.5 text-gray-400" size={18} />
                            <input 
                                type="password" 
                                className="w-full border pl-10 p-2 rounded-lg focus:ring-2 focus:ring-galaxy-500 outline-none"
                                value={password}
                                onChange={e => setPassword(e.target.value)}
                                placeholder="••••••••"
                                required
                            />
                        </div>
                    </div>
                    <div className="text-right">
                        <span className="text-xs text-gray-400">(Default password for demo: password)</span>
                    </div>
                    <button type="submit" className="w-full bg-galaxy-900 text-white py-3 rounded-lg hover:bg-galaxy-800 font-bold shadow-lg transform transition active:scale-95">
                        Login to Portal
                    </button>
                </form>

                {email === 'opentesting' && (
                    <div className="mt-8 pt-6 border-t border-gray-100 animate-in fade-in slide-in-from-top-2">
                        <label className="block text-xs font-bold text-red-500 uppercase mb-2 flex items-center gap-1">
                            <TestTube size={14} /> For Testing Only
                        </label>
                        <select
                            className="w-full text-sm border border-red-200 bg-red-50 text-red-800 rounded-lg p-2.5 focus:outline-none focus:ring-2 focus:ring-red-300"
                            onChange={(e) => {
                                const selectedEmail = e.target.value;
                                if(!selectedEmail) return;
                                const user = state.users.find(u => u.email === selectedEmail);
                                if(user) dispatch({ type: 'LOGIN', payload: user });
                            }}
                            defaultValue=""
                        >
                            <option value="" disabled>-- Quick Login As Role --</option>
                            <option value="admin@galaxy.edu.np">Admin (Super Admin)</option>
                            <option value="suresh@galaxy.edu.np">Admin (Suresh Pradhan)</option>
                            <option value="ramesh@galaxy.edu.np">Accountant (Ramesh Adhikari)</option>
                            <option value="sarita@galaxy.edu.np">Teacher (Sarita Sharma)</option>
                            <option value="ram@galaxy.edu.np">Student (Ram Kafle)</option>
                            <option value="hari@galaxy.edu.np">Intern (Hari Shrestha)</option>
                            <option value="dheejan@gmail.com">Developer</option>
                        </select>
                    </div>
                )}
                </>
            ) : (
                <form onSubmit={handleRegister} className="space-y-3 h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                     <div>
                        <label className="block text-sm font-medium text-gray-700">Account Type</label>
                        <select 
                            className="w-full border p-2 rounded mt-1 bg-gray-50"
                            value={regForm.role}
                            onChange={e => setRegForm({...regForm, role: e.target.value as Role})}
                            required
                        >
                            <option value="student">Student</option>
                            <option value="intern">Intern</option>
                            <option value="teacher">Teacher</option>
                            <option value="accountant">Accountant</option>
                            <option value="admin">Admin</option>
                        </select>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                         <div>
                            <label className="block text-sm font-medium text-gray-700">Full Name</label>
                            <input 
                                type="text" required
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.name}
                                onChange={e => setRegForm({...regForm, name: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Email</label>
                            <input 
                                type="email" required
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.email}
                                onChange={e => setRegForm({...regForm, email: e.target.value})}
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                         <div>
                            <label className="block text-sm font-medium text-gray-700">Phone</label>
                            <input 
                                type="text"
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.phone}
                                onChange={e => setRegForm({...regForm, phone: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Set Password</label>
                            <input 
                                type="password" required
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.password}
                                onChange={e => setRegForm({...regForm, password: e.target.value})}
                                minLength={6}
                                placeholder="Min 6 chars"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Address</label>
                        <input 
                            type="text"
                            className="w-full border p-2 rounded mt-1"
                            value={regForm.address}
                            onChange={e => setRegForm({...regForm, address: e.target.value})}
                        />
                    </div>

                     {/* Student Specific Fields */}
                     {regForm.role === 'student' && (
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 space-y-2">
                            <h4 className="font-semibold text-blue-800 text-xs uppercase">Student Details</h4>
                            <div className="grid grid-cols-2 gap-2">
                                <div>
                                    <label className="block text-xs font-medium text-gray-700">Class / Batch</label>
                                    <select 
                                        required
                                        className="w-full border p-2 rounded mt-1 text-sm bg-white"
                                        value={regForm.classId}
                                        onChange={e => setRegForm({...regForm, classId: e.target.value, section: ''})}
                                    >
                                        <option value="">-- Select Class --</option>
                                        {state.systemClasses.map(cls => (
                                            <option key={cls.name} value={cls.name}>{cls.name}</option>
                                        ))}
                                    </select>
                                </div>
                                {selectedClassData && selectedClassData.sections.length > 0 && (
                                    <div>
                                        <label className="block text-xs font-medium text-gray-700">Section</label>
                                        <select 
                                            required
                                            className="w-full border p-2 rounded mt-1 text-sm bg-white"
                                            value={regForm.section}
                                            onChange={e => setRegForm({...regForm, section: e.target.value})}
                                        >
                                            <option value="">-- Select Section --</option>
                                            {selectedClassData.sections.map(sec => (
                                                <option key={sec} value={sec}>{sec}</option>
                                            ))}
                                        </select>
                                    </div>
                                )}
                            </div>
                            <div className="text-xs text-blue-600 italic mt-1">
                                Fees and discounts will be assigned by the administration upon approval.
                            </div>
                        </div>
                    )}

                    {/* Teacher Specific Fields */}
                    {regForm.role === 'teacher' && (
                        <div className="bg-purple-50 p-3 rounded-lg border border-purple-100">
                            <h4 className="font-semibold text-purple-800 text-xs uppercase mb-2">Select Subjects</h4>
                            <div className="flex flex-wrap gap-2">
                                {state.availableSubjects.map(subject => {
                                    const isSelected = regForm.subjects?.includes(subject.name);
                                    return (
                                        <button
                                            key={subject.name}
                                            type="button"
                                            onClick={() => toggleSubject(subject.name)}
                                            className={`text-xs px-2 py-1 rounded-full border transition-all ${
                                                isSelected 
                                                ? 'bg-purple-600 text-white border-purple-600' 
                                                : 'bg-white text-gray-600 border-gray-300 hover:border-purple-400'
                                            }`}
                                        >
                                            {subject.name} <span className="text-[10px] opacity-75">({subject.type[0]})</span> {isSelected && '✓'}
                                        </button>
                                    )
                                })}
                            </div>
                            {(regForm.subjects?.length || 0) === 0 && (
                                <p className="text-xs text-red-400 mt-2">* Please select at least one subject</p>
                            )}
                        </div>
                    )}

                    <button type="submit" className="w-full bg-galaxy-600 text-white py-2 rounded-lg hover:bg-galaxy-700 font-semibold shadow-sm mt-4">
                        Register Account
                    </button>
                </form>
            )}
        </div>

      </div>
    </div>
  );
};

